def perceive(data):
    text = str(data).lower()
    idx = text.find("glucose")
    if idx >= 0:
        text = text[idx + len("glucose"):]
    num = ""
    for ch in text:
        if ch.isdigit() or ch == ".":
            num += ch
        elif num:
            break
    if not num:
        return {}
    return {"glucose": round(float(num), 2)}
